27:      .describe('Filter by provider name (e.g. "claude-code")'),
28:    conversationId: z.string().optional()
29:      .describe('Filter by conversation id'),
30:    limit: z.number().optional().default(20)
31:      .describe('Maximum results (default: 20)'),
32:  },
33:  permission: 'read',
34:  handler: async (params) => {
35:    const stacks = guild().apparatus<StacksApi>('stacks');
36:    const sessions = stacks.readBook<SessionDoc>('animator', 'sessions');
38:    const where: WhereCondition[] = [];
39:    if (params.status) where.push(['status', '=', params.status]);
40:    if (params.provider) where.push(['provider', '=', params.provider]);
41:    if (params.conversationId) where.push(['conversationId', '=', params.conversationId]);
43:    const results = await sessions.find({
44:      where: where.length > 0 ? where : undefined,
45:      orderBy: ['startedAt', 'desc'],
46:      limit: params.limit,
47:    });
49:    // Return summary projection
50:    return results.map((s) => ({
51:      id: s.id,
52:      status: s.status,
53:      provider: s.provider,
54:      startedAt: s.startedAt,
55:      endedAt: s.endedAt,
56:      durationMs: s.durationMs,
57:      exitCode: s.exitCode,
58:      costUsd: s.costUsd,
59:    }));
60:  },
61:});

