1:/**
2: * Animator tests.
3: *
4: * Uses a fake session provider apparatus and in-memory Stacks backend to
5: * test the full animate() lifecycle without spawning real processes.
6: *
7: * The fake provider is registered as an apparatus in the guild mock,
8: * matching how real providers work (the Animator discovers them via
9: * guild().apparatus(config.sessionProvider)).
10: */
12:import { describe, it, beforeEach, afterEach } from 'node:test';
13:import assert from 'node:assert/strict';
15:import { setGuild, clearGuild } from '@shardworks/nexus-core';
16:import type { Guild } from '@shardworks/nexus-core';
17:import { createStacksApparatus } from '@shardworks/stacks-apparatus';
18:import { MemoryBackend } from '@shardworks/stacks-apparatus/testing';
19:import type { StacksApi } from '@shardworks/stacks-apparatus';
21:import { createLoom } from '@shardworks/loom-apparatus';
22:import type { LoomApi } from '@shardworks/loom-apparatus';
24:import { createAnimator } from './animator.ts';
25:import type {
26:  AnimatorApi,
27:  AnimatorSessionProvider,
28:  SessionProviderConfig,
29:  SessionProviderResult,
30:  SessionChunk,
31:  SessionDoc,
32:  TranscriptDoc,
33:} from './types.ts';
35:// ── Shared empty chunks iterable ─────────────────────────────────────
37:const emptyChunks: AsyncIterable<SessionChunk> = {
38:  [Symbol.asyncIterator]() {
39:    return {
40:      async next() {
41:        return { value: undefined as unknown as SessionChunk, done: true as const };
42:      },
43:    };
44:  },
45:};
47:// ── Fake providers ───────────────────────────────────────────────────
49:function createFakeProvider(
50:  overrides: Partial<SessionProviderResult> = {},
51:): AnimatorSessionProvider {
52:  return {
53:    name: 'fake',
54:    launch(_config: SessionProviderConfig) {
55:      return {
56:        chunks: emptyChunks,
57:        result: Promise.resolve({
58:          status: 'completed' as const,
59:          exitCode: 0,
60:          providerSessionId: 'fake-sess-123',
61:          tokenUsage: {
62:            inputTokens: 1000,
63:            outputTokens: 500,
64:          },
65:          costUsd: 0.05,
66:          ...overrides,
67:        }),
68:      };
69:    },
70:  };
71:}
73:function createStreamingFakeProvider(
74:  streamChunks: SessionChunk[],
75:  overrides: Partial<SessionProviderResult> = {},
76:): AnimatorSessionProvider {
77:  return {
78:    name: 'fake-streaming',
79:    launch(config: SessionProviderConfig) {
80:      if (config.streaming) {
81:        let idx = 0;
82:        const asyncChunks: AsyncIterable<SessionChunk> = {
83:          [Symbol.asyncIterator]() {
84:            return {
85:              async next() {
86:                if (idx < streamChunks.length) {
