9	 */
10	
11	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
12	import { guild, generateId } from '@shardworks/nexus-core';
13	import type { StacksApi, Book } from '@shardworks/stacks-apparatus';
14	
15	import type { LoomApi } from '@shardworks/loom-apparatus';
16	
17	import type {
18	  AnimatorApi,
19	  AnimateHandle,
20	  AnimatorConfig,
21	  AnimateRequest,
22	  SummonRequest,
23	  SessionResult,
24	  SessionChunk,
25	  SessionDoc,
26	  TranscriptDoc,
27	  TranscriptMessage,
28	  AnimatorSessionProvider,
29	  SessionProviderConfig,
30	  SessionProviderResult,
31	} from './types.ts';
32	
33	import { sessionList, sessionShow, summon as summonTool } from './tools/index.ts';
34	
35	// ── Session broadcast infrastructure ─────────────────────────────────
36	
37	/**
38	 * A single subscriber within a session broadcaster.
39	 * Chunks are queued here until the consumer iterates them.
40	 */
41	interface BroadcastSubscriber {
42	  queue: SessionChunk[];
43	  notify: (() => void) | null;
44	  done: boolean;
45	}
46	
47	/**
48	 * An in-process broadcast channel for a single running session.
49	 *
50	 * Multiple consumers can subscribe and each receives all chunks from the
51	 * beginning of the session (history replay) plus any future chunks.
52	 * When the session ends, all subscriptions complete.
53	 */
54	interface SessionBroadcaster {
55	  push(chunk: SessionChunk): void;
56	  close(): void;
57	  subscribe(): AsyncIterable<SessionChunk>;
58	}
59	
60	function createSessionBroadcaster(): SessionBroadcaster {
61	  const history: SessionChunk[] = [];
62	  const subscribers: BroadcastSubscriber[] = [];
63	  let closed = false;
64	
65	  function push(chunk: SessionChunk): void {
66	    history.push(chunk);
67	    for (const sub of subscribers) {
68	      if (!sub.done) {
69	        sub.queue.push(chunk);
70	        if (sub.notify) {
71	          const notify = sub.notify;
72	          sub.notify = null;
73	          notify();
74	        }
75	      }
76	    }
77	  }
78	
79	  function close(): void {
80	    closed = true;
81	    for (const sub of subscribers) {
82	      sub.done = true;
83	      if (sub.notify) {
84	        const notify = sub.notify;
85	        sub.notify = null;
86	        notify();
87	      }
88	    }
89	  }
90	
91	  function subscribe(): AsyncIterable<SessionChunk> {
92	    // New subscriber starts with full history replay, then receives future chunks.
93	    const sub: BroadcastSubscriber = {
94	      queue: [...history],
95	      notify: null,
96	      done: closed,
97	    };
98	    if (!closed) {
99	      subscribers.push(sub);
100	    }
101	    return {
102	      [Symbol.asyncIterator]() {
103	        return {
104	          async next() {
105	            while (sub.queue.length === 0 && !sub.done) {
106	              await new Promise<void>((resolve) => {
107	                sub.notify = resolve;
108	              });
109	            }
110	            if (sub.queue.length > 0) {
111	              return { value: sub.queue.shift()!, done: false as const };
112	            }
113	            return { value: undefined as unknown as SessionChunk, done: true as const };
114	          },
115	        };
116	      },
117	    };
118	  }
119	
120	  return { push, close, subscribe };
121	}
122	
123	// ── Core logic ───────────────────────────────────────────────────────
124	
125	/**
126	 * Resolve the session provider apparatus.
127	 *
128	 * Looks up the provider by plugin id from guild config. The provider is
129	 * an apparatus whose `provides` implements AnimatorSessionProvider.
130	 * Arbor throws immediately if the plugin isn't loaded or has no provides.
131	 */
132	function resolveProvider(config: AnimatorConfig): AnimatorSessionProvider {
133	  const pluginId = config.sessionProvider ?? 'claude-code';
134	  return guild().apparatus<AnimatorSessionProvider>(pluginId);
135	}
136	
137	/**
138	 * Resolve the model from guild settings.
139	 */
140	function resolveModel(): string {
141	  const g = guild();
142	  const guildConfig = g.guildConfig();
143	  return guildConfig.settings?.model ?? 'sonnet';
144	}
145	
146	/**
147	 * Build the provider config from an AnimateRequest.
148	 *
149	 * The system prompt comes from the AnimaWeave (composed by The Loom).
150	 * The work prompt comes from the request directly (bypasses The Loom).
151	 * The streaming flag is passed through for the provider to honor (or ignore).
152	 */
153	/**
154	 * Build a working-directory preamble that tells the agent where it is.
155	 *
156	 * Claude Code tools (Glob, Grep) return relative paths; the agent must
157	 * construct absolute paths for Read/Edit/Write. Without an explicit
158	 * preamble the agent guesses — and when other checkouts exist on the
159	 * filesystem (e.g. /workspace/nexus/) it routinely guesses wrong,
160	 * committing to the persistent clone instead of its worktree.
161	 */
162	function cwdPreamble(cwd: string): string {
163	  return [
164	    `Your working directory is: ${cwd}`,
165	    'All file operations (Read, Edit, Write, Glob, Grep) must use paths rooted in this directory.',
166	    'Do NOT read, write, or explore files outside this directory.',
167	    '',
168	  ].join('\n');
169	}
170	
171	function buildProviderConfig(
172	  request: AnimateRequest,
173	  model: string,
174	): SessionProviderConfig {
175	  // Prepend cwd preamble to the initial prompt so the agent knows where
176	  // it is. Skip for resumed conversations — the preamble was already
177	  // delivered in the original session's first message.
178	  const prompt = request.conversationId
179	    ? request.prompt
180	    : cwdPreamble(request.cwd) + (request.prompt ?? '');
181	
182	  return {
183	    systemPrompt: request.context.systemPrompt,
184	    initialPrompt: prompt,
185	    model,
186	    conversationId: request.conversationId,
187	    cwd: request.cwd,
188	    streaming: request.streaming,
189	    tools: request.context.tools,
190	    environment: { ...request.context.environment, ...request.environment },
191	  };
192	}
193	
194	/**
195	 * Build a SessionResult from provider output and session metadata.
196	 */
197	function buildSessionResult(
198	  id: string,
199	  startedAt: string,
200	  providerName: string,
201	  providerResult: SessionProviderResult,
202	  request: AnimateRequest,
203	): SessionResult {
204	  const endedAt = new Date().toISOString();
205	  const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();
206	
207	  return {
208	    id,
209	    status: providerResult.status,
210	    startedAt,
211	    endedAt,
212	    durationMs,
213	    provider: providerName,
214	    exitCode: providerResult.exitCode,
215	    error: providerResult.error,
216	    conversationId: request.conversationId,
217	    providerSessionId: providerResult.providerSessionId,
218	    tokenUsage: providerResult.tokenUsage,
219	    costUsd: providerResult.costUsd,
220	    metadata: request.metadata,
221	    output: providerResult.output,
222	  };
223	}
224	
225	/**
226	 * Build a failed SessionResult when the provider throws.
227	 */
228	function buildFailedResult(
229	  id: string,
230	  startedAt: string,
231	  providerName: string,
232	  error: unknown,
233	  request: AnimateRequest,
234	): SessionResult {
235	  const endedAt = new Date().toISOString();
236	  const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();
237	  const errorMessage = error instanceof Error ? error.message : String(error);
238	
239	  return {
240	    id,
241	    status: 'failed',
242	    startedAt,
243	    endedAt,
244	    durationMs,
245	    provider: providerName,
246	    exitCode: 1,
247	    error: errorMessage,
248	    conversationId: request.conversationId,
249	    metadata: request.metadata,
250	  };
251	}
252	
253	/**
254	 * Convert a SessionResult to a SessionDoc for Stacks storage.
255	 */
256	function toSessionDoc(result: SessionResult): SessionDoc {
257	  return {
258	    id: result.id,
259	    status: result.status,
260	    startedAt: result.startedAt,
261	    endedAt: result.endedAt,
262	    durationMs: result.durationMs,
263	    provider: result.provider,
264	    exitCode: result.exitCode,
265	    error: result.error,
266	    conversationId: result.conversationId,
267	    providerSessionId: result.providerSessionId,
268	    tokenUsage: result.tokenUsage,
269	    costUsd: result.costUsd,
270	    metadata: result.metadata,
271	    output: result.output,
272	  };
273	}
274	
275	/**
276	 * Record a session result to The Stacks (sessions + transcripts books).
277	 *
278	 * Errors are logged but never propagated — session data loss is
279	 * preferable to masking the original failure. See § Error Handling Contract.
280	 */
281	async function recordSession(
282	  sessions: Book<SessionDoc>,
283	  transcripts: Book<TranscriptDoc>,
284	  result: SessionResult,
285	  transcript: TranscriptMessage[] | undefined,
286	): Promise<void> {
287	  try {
288	    await sessions.put(toSessionDoc(result));
289	  } catch (err) {
290	    console.warn(
291	      `[animator] Failed to record session ${result.id}: ${err instanceof Error ? err.message : err}`,
292	    );
293	  }
294	
295	  if (transcript && transcript.length > 0) {
296	    try {
297	      await transcripts.put({ id: result.id, messages: transcript });
298	    } catch (err) {
299	      console.warn(
300	        `[animator] Failed to record transcript for ${result.id}: ${err instanceof Error ? err.message : err}`,
301	      );
302	    }
303	  }
304	}
305	
306	/**
307	 * Write the initial 'running' session record to The Stacks.
308	 */
309	async function recordRunning(
310	  sessions: Book<SessionDoc>,
311	  id: string,
312	  startedAt: string,
313	  providerName: string,
314	  request: AnimateRequest,
315	): Promise<void> {
316	  try {
317	    await sessions.put({
318	      id,
319	      status: 'running',
320	      startedAt,
321	      provider: providerName,
322	      conversationId: request.conversationId,
323	      metadata: request.metadata,
324	    });
325	  } catch (err) {
326	    console.warn(
327	      `[animator] Failed to write initial session record ${id}: ${err instanceof Error ? err.message : err}`,
328	    );
329	  }
330	}
331	
332	// ── Apparatus factory ────────────────────────────────────────────────
333	
334	/**
335	 * Create the Animator apparatus plugin.
336	 *
337	 * Returns a Plugin with:
338	 * - `requires: ['stacks']` — records session results
339	 * - `provides: AnimatorApi` — the session launch API
340	 * - `supportKit` — contributes `sessions` book + inspection tools
341	 */
342	export function createAnimator(): Plugin {
343	  let config: AnimatorConfig = {};
344	  let sessions: Book<SessionDoc>;
345	  let transcripts: Book<TranscriptDoc>;
346	
347	  /**
348	   * In-memory registry of active session broadcasters.
349	   * Keyed by session id. Entries are removed ~30 s after the session ends,
350	   * which gives late SSE subscribers time to drain any buffered chunks.
351	   */
352	  const activeSessions = new Map<string, SessionBroadcaster>();
353	
354	  const api: AnimatorApi = {
355	    subscribeToSession(sessionId: string): AsyncIterable<SessionChunk> | null {
356	      const broadcaster = activeSessions.get(sessionId);
357	      if (!broadcaster) return null;
358	      return broadcaster.subscribe();
359	    },
360	
361	    summon(request: SummonRequest): AnimateHandle {
362	      // Resolve The Loom at call time — not a startup dependency.
363	      // This allows the Animator to start without the Loom installed;
364	      // only summon() requires it.
365	      let loom: LoomApi;
366	      try {
367	        loom = guild().apparatus<LoomApi>('loom');
368	      } catch {
369	        throw new Error(
370	          'summon() requires The Loom apparatus to be installed. ' +
371	          'Use animate() directly if you want to provide a pre-composed AnimaWeave.',
372	        );
373	      }
374	
375	      // Generate session id up front so it's available on the handle
376	      // immediately — before the Loom weave or session launch resolves.
377	      const sessionId = generateId('ses', 4);
378	
379	      // We need to weave context before we can animate, but summon()
380	      // must return synchronously. Wrap the async Loom call and the
381	      // animate delegation into a single deferred flow.
382	      const deferred = (async () => {
383	        // Compose identity context via The Loom.
384	        // The Loom owns system prompt composition — it produces the system
385	        // prompt from the anima's identity layers (role instructions,
386	        // curriculum, temperament, charter). MVP: returns empty (no
387	        // systemPrompt); the session runs without one until the Loom
388	        // gains composition logic. The work prompt bypasses the Loom.
389	        const context = await loom.weave({
390	          role: request.role,
391	        });
392	
393	        // Merge caller metadata with auto-generated summon metadata
394	        const metadata: Record<string, unknown> = {
395	          trigger: 'summon',
396	          ...(request.role ? { role: request.role } : {}),
397	          ...request.metadata,
398	        };
399	
400	        // Delegate to the standard animate path, threading through the
401	        // pre-generated session id so animate() uses it instead of
402	        // generating a new one.
403	        return this.animate({
404	          sessionId,
405	          context,
406	          prompt: request.prompt,
407	          cwd: request.cwd,
408	          conversationId: request.conversationId,
409	          metadata,
410	          streaming: request.streaming,
411	          environment: request.environment,
412	        });
413	      })();
414	
415	      // Pipe chunks through — can't get them until the Loom weave resolves.
416	      // Works for both streaming and non-streaming: non-streaming providers
417	      // return empty chunks, so the generator yields nothing and completes.
418	      async function* pipeChunks(): AsyncIterable<SessionChunk> {
419	        const handle = await deferred;
420	        yield* handle.chunks;
421	      }
422	
423	      return {
424	        sessionId,
425	        chunks: pipeChunks(),
426	        result: deferred.then((handle) => handle.result),
427	      };
428	    },
429	
430	    animate(request: AnimateRequest): AnimateHandle {
431	      const provider = resolveProvider(config);
432	      const model = resolveModel();
433	      const providerConfig = buildProviderConfig(request, model);
434	
435	      // Step 1: use pre-generated session id if provided (from summon()),
436	      // otherwise generate one. Capture startedAt.
437	      const id = request.sessionId ?? generateId('ses', 4);
438	      const startedAt = new Date().toISOString();
439	
440	      // Single path — the provider returns { chunks, result } regardless
441	      // of whether streaming is enabled. Providers that don't support
442	      // streaming return empty chunks; the Animator doesn't branch.
443	      const { chunks: providerChunks, result: providerResultPromise } = provider.launch(providerConfig);
444	
445	      // Set up an in-process broadcaster for this session.
446	      // All chunks are fanned out through the broadcaster so that both the
447	      // returned handle.chunks and any subscribeToSession() callers receive
448	      // the full stream with history replay for late subscribers.
449	      const broadcaster = createSessionBroadcaster();
450	      activeSessions.set(id, broadcaster);
451	
452	      // Consume provider chunks in the background and push to the broadcaster.
453	      // This drives the fan-out to all subscribers (including handle.chunks).
454	      (async () => {
455	        try {
456	          for await (const chunk of providerChunks) {
457	            broadcaster.push(chunk);
458	          }
459	        } catch (err) {
460	          console.warn(
461	            `[animator] Error consuming chunks for session ${id}: ${err instanceof Error ? err.message : err}`,
462	          );
463	        } finally {
464	          broadcaster.close();
465	        }
466	      })();
467	
468	      // Write initial record (fire and forget — don't block streaming)
469	      const initPromise = recordRunning(sessions, id, startedAt, provider.name, request);
470	
471	      const result = (async () => {
472	        await initPromise;
473	
474	        let sessionResult: SessionResult;
475	        try {
476	          const providerResult = await providerResultPromise;
477	          sessionResult = buildSessionResult(id, startedAt, provider.name, providerResult, request);
478	          await recordSession(sessions, transcripts, sessionResult, providerResult.transcript);
479	        } catch (err) {
480	          sessionResult = buildFailedResult(id, startedAt, provider.name, err, request);
481	          await recordSession(sessions, transcripts, sessionResult, undefined);
482	          throw err;
483	        } finally {
484	          // Remove the broadcaster after a short delay so that any late-connecting
485	          // SSE subscribers can still drain buffered chunks before the entry disappears.
486	          setTimeout(() => activeSessions.delete(id), 30_000);
487	        }
488	        return sessionResult;
489	      })();
490	
491	      // The handle's chunks is a broadcaster subscription, providing history
492	      // replay and real-time delivery for this session's caller.
493	      return { sessionId: id, chunks: broadcaster.subscribe(), result };
494	    },
495	  };
496	
497	  return {
498	    apparatus: {
499	      requires: ['stacks'],
500	      recommends: ['loom'],
501	
502	      supportKit: {
503	        books: {
504	          sessions: {
505	            indexes: ['startedAt', 'status', 'conversationId', 'provider'],
506	          },
507	          transcripts: {
508	            indexes: ['sessionId'],
509	          },
510	        },
511	        tools: [sessionList, sessionShow, summonTool],
512	      },
513	
514	      provides: api,
515	
516	      start(_ctx: StartupContext): void {
517	        const g = guild();
518	        config = g.guildConfig().animator ?? {};
519	
520	        const stacks = g.apparatus<StacksApi>('stacks');
521	        sessions = stacks.book<SessionDoc>('animator', 'sessions');
522	        transcripts = stacks.book<TranscriptDoc>('animator', 'transcripts');
523	      },
524	    },
525	  };
526	}
